import type { ColumnSchema } from "lemma-sdk";

const ENUM_PALETTE = [
  { bg: "bg-blue-100 dark:bg-blue-500/15", text: "text-blue-700 dark:text-blue-300" },
  { bg: "bg-emerald-100 dark:bg-emerald-500/15", text: "text-emerald-700 dark:text-emerald-300" },
  { bg: "bg-violet-100 dark:bg-violet-500/15", text: "text-violet-700 dark:text-violet-300" },
  { bg: "bg-orange-100 dark:bg-orange-500/15", text: "text-orange-700 dark:text-orange-300" },
  { bg: "bg-pink-100 dark:bg-pink-500/15", text: "text-pink-700 dark:text-pink-300" },
  { bg: "bg-indigo-100 dark:bg-indigo-500/15", text: "text-indigo-700 dark:text-indigo-300" },
  { bg: "bg-teal-100 dark:bg-teal-500/15", text: "text-teal-700 dark:text-teal-300" },
  { bg: "bg-amber-100 dark:bg-amber-500/15", text: "text-amber-700 dark:text-amber-300" },
  { bg: "bg-cyan-100 dark:bg-cyan-500/15", text: "text-cyan-700 dark:text-cyan-300" },
  { bg: "bg-rose-100 dark:bg-rose-500/15", text: "text-rose-700 dark:text-rose-300" },
] as const;

function stableIndex(value: string, count: number): number {
  let hash = 0;
  for (let i = 0; i < value.length; i++) {
    hash = ((hash << 5) - hash + value.charCodeAt(i)) | 0;
  }
  return ((Math.abs(hash) % count) + count) % count;
}

export function enumColor(optionValue: string, options: string[]) {
  const idx = options.indexOf(optionValue);
  const i = idx >= 0 ? idx % ENUM_PALETTE.length : stableIndex(optionValue, ENUM_PALETTE.length);
  return ENUM_PALETTE[i];
}

export function enumPillClasses(optionValue: string, options: string[]): string {
  const c = enumColor(optionValue, options);
  return `inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${c.bg} ${c.text}`;
}

const TYPE_TINTS: Record<string, { bg: string; text: string }> = {
  TEXT: { bg: "bg-muted/45", text: "text-muted-foreground" },
  INTEGER: { bg: "bg-emerald-500/10", text: "text-emerald-700 dark:text-emerald-300" },
  FLOAT: { bg: "bg-blue-500/10", text: "text-blue-700 dark:text-blue-300" },
  BOOLEAN: { bg: "bg-primary/10", text: "text-primary" },
  DATE: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
  DATETIME: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
  ENUM: { bg: "bg-violet-500/10", text: "text-violet-700 dark:text-violet-300" },
  JSON: { bg: "bg-rose-500/10", text: "text-rose-700 dark:text-rose-300" },
  UUID: { bg: "bg-sky-500/10", text: "text-sky-700 dark:text-sky-300" },
  SERIAL: { bg: "bg-emerald-500/10", text: "text-emerald-700 dark:text-emerald-300" },
  VECTOR: { bg: "bg-muted/45", text: "text-muted-foreground" },
};

export function typeBadgeClasses(column: ColumnSchema): string {
  const tint = TYPE_TINTS[column.type] ?? TYPE_TINTS.TEXT;
  if (column.foreign_key) {
    return "rounded-full border border-border/50 bg-sky-500/10 px-1.5 py-0.5 text-[9px] font-medium normal-case text-sky-700 dark:text-sky-300";
  }
  return `rounded-full border border-border/50 ${tint.bg} px-1.5 py-0.5 text-[9px] font-medium normal-case ${tint.text}`;
}

export function isSystemField(column: ColumnSchema): boolean {
  return (
    column.system === true ||
    column.auto === true ||
    column.computed === true ||
    column.name === "id" ||
    column.name === "created_at" ||
    column.name === "updated_at" ||
    column.name === "creator_user_id" ||
    column.name === "sort_order"
  );
}

"use client"

import * as React from "react"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses, isSystemField } from "./records-enum-utils"

export type ForeignKeyLabelMap = Record<string, Record<string, string>>

const PRIMARY_FIELD_NAMES = ["title", "name", "label", "subject", "full_name", "primary_email"]

export function isUuidLike(value: string): boolean {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(value)
}

export function shortenIdentifier(value: unknown): string {
  const text = String(value ?? "")
  if (!text) return "—"
  if (isUuidLike(text)) return `${text.slice(0, 8)}…${text.slice(-4)}`
  return text.length > 28 ? `${text.slice(0, 24)}…` : text
}

export function pickPrimaryColumn(columns: ColumnSchema[]): ColumnSchema | undefined {
  return (
    columns.find((column) => PRIMARY_FIELD_NAMES.includes(column.name)) ??
    columns.find((column) => !isSystemField(column) && !column.foreign_key) ??
    columns.find((column) => !isSystemField(column)) ??
    columns[0]
  )
}

export function pickSecondaryColumns(
  columns: ColumnSchema[],
  primaryColumn?: ColumnSchema,
  options: { groupBy?: string; count?: number } = {},
): ColumnSchema[] {
  const count = options.count ?? 4
  return columns
    .filter((column) => !isSystemField(column))
    .filter((column) => column.name !== primaryColumn?.name)
    .filter((column) => column.name !== options.groupBy)
    .filter((column) => column.type !== "VECTOR" && column.type !== "JSON")
    .slice(0, count)
}

export function formatRecordFieldValue(
  value: unknown,
  column?: ColumnSchema,
  foreignKeyLabelMap?: ForeignKeyLabelMap,
): React.ReactNode {
  if (value == null || value === "") return "—"

  const text = String(value)
  if (column?.foreign_key) {
    const label = foreignKeyLabelMap?.[column.name]?.[text]
    return label || shortenIdentifier(text)
  }

  if (column?.type === "ENUM" && column.options?.length) {
    return <span className={enumPillClasses(text, column.options)}>{text}</span>
  }

  if (column?.type === "BOOLEAN") return value ? "Yes" : "No"

  if (column?.type === "DATE" || column?.type === "DATETIME") {
    const date = new Date(text)
    if (!Number.isNaN(date.getTime())) {
      return date.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" })
    }
  }

  if (column?.type === "UUID" || isUuidLike(text)) {
    return <span title={text}>{shortenIdentifier(text)}</span>
  }

  return text
}

"use client"

import * as React from "react"
import { Check, Loader2 } from "lucide-react"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Checkbox } from "@/components/ui/checkbox"
import { Textarea } from "@/components/ui/textarea"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses } from "./records-enum-utils"
import { shortenIdentifier } from "./records-display-utils"

interface EditableCellProps {
  value: unknown
  column: ColumnSchema
  onSave: (value: unknown) => Promise<void>
  readOnly?: boolean
  foreignKeyLabelMap?: Record<string, string>
}

export function EditableCell({ value, column, onSave, readOnly, foreignKeyLabelMap }: EditableCellProps) {
  const [editing, setEditing] = React.useState(false)
  const [draft, setDraft] = React.useState<string>(serialize(value, column.type))
  const [saving, setSaving] = React.useState(false)
  const inputRef = React.useRef<HTMLInputElement | HTMLTextAreaElement | null>(null)

  React.useEffect(() => {
    if (editing && inputRef.current) inputRef.current.focus()
  }, [editing])

  const startEdit = () => {
    if (readOnly) return
    setDraft(serialize(value, column.type))
    setEditing(true)
  }

  const save = async () => {
    const next = deserialize(draft, column)
    if (next === value && column.type !== "BOOLEAN") {
      setEditing(false)
      return
    }
    setSaving(true)
    try {
      await onSave(next)
      setEditing(false)
    } finally {
      setSaving(false)
    }
  }

  const cancel = () => {
    setDraft(serialize(value, column.type))
    setEditing(false)
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey && column.type !== "TEXT") save()
    if (e.key === "Escape") cancel()
  }

  if (readOnly) {
    return <span className="px-2 py-1.5 text-sm text-muted-foreground">{displayValue(value, column, foreignKeyLabelMap)}</span>
  }

  if (column.type === "BOOLEAN") {
    return (
      <label className="flex min-h-[32px] cursor-pointer items-center gap-2 px-2 py-1.5">
        <Checkbox
          checked={Boolean(value)}
          onCheckedChange={(checked) => onSave(checked === true)}
          disabled={saving}
        />
        <span className="text-xs text-muted-foreground">{value ? "Yes" : "No"}</span>
      </label>
    )
  }

  if (column.type === "ENUM" && column.options && column.options.length) {
    const opts = column.options
    return (
      <Select
        value={String(value ?? "")}
        onValueChange={(v) => onSave(v)}
        disabled={saving}
      >
        <SelectTrigger className="h-8 gap-1 border-transparent bg-transparent px-2 text-xs shadow-none hover:border-border hover:bg-muted/50">
          {value != null ? (
            <span className={enumPillClasses(String(value), opts)}>
              {String(value)}
            </span>
          ) : (
            <SelectValue placeholder="—" />
          )}
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {opts.map((opt) => (
              <SelectItem key={opt} value={opt}>
                <span className={enumPillClasses(opt, opts)}>{opt}</span>
              </SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (editing) {
    const isLong = column.type === "TEXT" && (column.max_length ?? 0) > 200
    const isJson = column.type === "JSON"

    if (isLong || isJson) {
      return (
        <div className="relative min-h-[32px] w-full px-1 py-0.5">
          <Textarea
            ref={inputRef as React.Ref<HTMLTextAreaElement>}
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            onKeyDown={handleKeyDown}
            onBlur={save}
            rows={3}
            className="min-h-[60px] resize-none border-border bg-background text-sm font-mono placeholder:text-muted-foreground focus-ring"
          />
          {saving && <Loader2 className="absolute right-2 top-2 h-3 w-3 animate-spin text-primary" />}
        </div>
      )
    }

    const inputType = column.type === "INTEGER" || column.type === "FLOAT" || column.type === "SERIAL"
      ? "number"
      : column.type === "DATE"
        ? "date"
        : column.type === "DATETIME"
          ? "datetime-local"
          : "text"

    return (
      <div className="relative min-h-[32px] w-full px-1 py-0.5">
        <Input
          ref={inputRef as React.Ref<HTMLInputElement>}
          type={inputType}
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={handleKeyDown}
          onBlur={save}
          className="h-8 border-border bg-background text-sm placeholder:text-muted-foreground focus-ring"
        />
        {saving && <Loader2 className="absolute right-2 top-2 h-3 w-3 animate-spin text-primary" />}
      </div>
    )
  }

  return (
    <div
      className="flex min-h-[32px] cursor-pointer items-center rounded-md border border-transparent px-2 py-1.5 text-sm transition-colors hover:border-border hover:bg-muted/50"
      onClick={startEdit}
    >
      {displayValue(value, column, foreignKeyLabelMap)}
    </div>
  )
}

function displayValue(
  value: unknown,
  column: ColumnSchema,
  foreignKeyLabelMap?: Record<string, string>,
): React.ReactNode {
  if (value == null || value === "") return <span className="text-muted-foreground">—</span>
  if (column.foreign_key) {
    const text = String(value)
    return foreignKeyLabelMap?.[text] ?? <span title={text}>{shortenIdentifier(text)}</span>
  }
  if (column.type === "BOOLEAN") return value ? "Yes" : "No"
  if (column.type === "ENUM" && column.options && column.options.length) {
    return <span className={enumPillClasses(String(value), column.options)}>{String(value)}</span>
  }
  if (column.type === "JSON") {
    const str = typeof value === "string" ? value : JSON.stringify(value, null, 2)
    return <span className="font-mono text-xs text-muted-foreground">{str.length > 60 ? str.slice(0, 57) + "…" : str}</span>
  }
  if (column.type === "DATE" || column.type === "DATETIME") {
    try {
      return new Date(String(value)).toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" })
    } catch {
      return String(value)
    }
  }
  if (column.type === "UUID" || (column.foreign_key && column.type === "TEXT")) {
    const s = String(value)
    return <span className="font-mono text-xs text-muted-foreground" title={s}>{shortenIdentifier(s)}</span>
  }
  return String(value)
}

function serialize(value: unknown, type: ColumnSchema["type"]): string {
  if (value == null) return ""
  if (type === "BOOLEAN") return value ? "true" : "false"
  if (type === "JSON") return typeof value === "string" ? value : JSON.stringify(value, null, 2)
  return String(value)
}

function deserialize(raw: string, column: ColumnSchema): unknown {
  const trimmed = raw.trim()
  if (trimmed === "") return null
  if (column.type === "INTEGER" || column.type === "SERIAL") return Number.parseInt(trimmed, 10)
  if (column.type === "FLOAT") return Number.parseFloat(trimmed)
  if (column.type === "BOOLEAN") return trimmed === "true"
  if (column.type === "JSON") {
    try { return JSON.parse(trimmed) } catch { return trimmed }
  }
  return trimmed
}

"use client"

import * as React from "react"
import { Plus, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import type { ColumnSchema, RecordFilter } from "lemma-sdk"

interface FilterBuilderProps {
  columns: ColumnSchema[]
  filters: RecordFilter[]
  onApply: (filters: RecordFilter[]) => void
  onClose: () => void
}

const OPERATORS = [
  { value: "eq", label: "is" },
  { value: "ne", label: "is not" },
  { value: "gt", label: ">" },
  { value: "gte", label: ">=" },
  { value: "lt", label: "<" },
  { value: "lte", label: "<=" },
  { value: "ilike", label: "contains" },
  { value: "starts_with", label: "starts with" },
  { value: "ends_with", label: "ends with" },
  { value: "in", label: "in" },
  { value: "is", label: "is empty" },
  { value: "is not", label: "is not empty" },
] as const

const EMPTY_VALUE = "__lemma_empty__"

function blank(columns: ColumnSchema[]): RecordFilter {
  return { field: columns[0]?.name ?? "", op: "eq", value: "" }
}

export function FilterBuilder({ columns, filters, onApply, onClose }: FilterBuilderProps) {
  const [rows, setRows] = React.useState<RecordFilter[]>(
    filters.length > 0 ? filters : [blank(columns)],
  )

  const update = <K extends keyof RecordFilter>(idx: number, key: K, val: RecordFilter[K]) => {
    setRows((prev) => {
      const next = [...prev]
      next[idx] = { ...next[idx], [key]: val }
      if (key === "field") {
        const col = columns.find((c) => c.name === val)
        if (col?.options?.length) next[idx] = { ...next[idx], op: "eq", value: "" }
      }
      return next
    })
  }

  const remove = (idx: number) => setRows((prev) => prev.filter((_, i) => i !== idx))

  const add = () => setRows((prev) => [...prev, blank(columns)])

  const apply = () => {
    onApply(
      rows.filter(
        (r) =>
          r.field &&
          (r.op === "is" || r.op === "is not" || String(r.value ?? "").trim() !== ""),
      ),
    )
    onClose()
  }

  const inputClass =
    "h-9 w-full rounded-md border border-border bg-background px-3 text-sm text-foreground placeholder:text-muted-foreground hover:border-foreground/20 focus-ring"

  const currentColumn = (field: string) => columns.find((c) => c.name === field)

  return (
    <Dialog open onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="max-w-2xl gap-0 overflow-hidden border-border/60 bg-background p-0">
        <div className="border-b border-border/50 px-6 py-5">
          <DialogHeader>
            <DialogTitle className="text-lg font-semibold tracking-tight">
              Filter Records
            </DialogTitle>
            <DialogDescription className="text-xs uppercase tracking-widest text-muted-foreground">
              Refine your view by adding conditions
            </DialogDescription>
          </DialogHeader>
        </div>

        <div className="max-h-[60vh] space-y-3 overflow-y-auto p-6">
          {rows.map((row, idx) => {
            const col = currentColumn(row.field)
            const needsValue = row.op !== "is" && row.op !== "is not"
            return (
              <div key={idx} className="group flex items-start gap-2">
                <div className="grid flex-1 grid-cols-1 gap-2 md:grid-cols-12">
                  <div className="md:col-span-4">
                    <Select
                      value={row.field}
                      onValueChange={(value) => {
                        if (value != null) update(idx, "field", value)
                      }}
                    >
                      <SelectTrigger className="h-9 w-full">
                        <SelectValue placeholder="Field" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectGroup>
                          {columns.map((c) => (
                            <SelectItem key={c.name} value={c.name}>
                              {c.name}
                            </SelectItem>
                          ))}
                        </SelectGroup>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="md:col-span-3">
                    <Select
                      value={row.op}
                      onValueChange={(value) => {
                        if (value != null) update(idx, "op", value)
                      }}
                    >
                      <SelectTrigger className="h-9 w-full">
                        <SelectValue placeholder="Operator" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectGroup>
                          {OPERATORS.map((o) => (
                            <SelectItem key={o.value} value={o.value}>
                              {o.label}
                            </SelectItem>
                          ))}
                        </SelectGroup>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="md:col-span-5">
                    {needsValue && col?.type === "ENUM" && col.options ? (
                      <Select
                        value={row.value == null || row.value === "" ? EMPTY_VALUE : String(row.value)}
                        onValueChange={(value) => update(idx, "value", value === EMPTY_VALUE ? "" : value)}
                      >
                        <SelectTrigger className="h-9 w-full">
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            <SelectItem value={EMPTY_VALUE}>—</SelectItem>
                            {col.options.map((opt) => (
                              <SelectItem key={opt} value={opt}>
                                {opt}
                              </SelectItem>
                            ))}
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    ) : needsValue && col?.type === "BOOLEAN" ? (
                      <Select
                        value={row.value == null || row.value === "" ? EMPTY_VALUE : String(row.value)}
                        onValueChange={(value) => update(idx, "value", value === EMPTY_VALUE ? "" : value === "true")}
                      >
                        <SelectTrigger className="h-9 w-full">
                          <SelectValue placeholder="Value" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectGroup>
                            <SelectItem value={EMPTY_VALUE}>—</SelectItem>
                            <SelectItem value="true">Yes</SelectItem>
                            <SelectItem value="false">No</SelectItem>
                          </SelectGroup>
                        </SelectContent>
                      </Select>
                    ) : needsValue ? (
                      <Input
                        value={String(row.value ?? "")}
                        onChange={(e) => update(idx, "value", e.target.value)}
                        placeholder="Value"
                        className={inputClass}
                      />
                    ) : (
                      <div className={inputClass + " flex items-center text-muted-foreground"}>
                        —
                      </div>
                    )}
                  </div>
                </div>
                <button
                  type="button"
                  onClick={() => remove(idx)}
                  className="rounded-lg p-2 text-muted-foreground transition-colors hover:bg-destructive/10 hover:text-destructive"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
            )
          })}

          <Button
            variant="ghost"
            size="sm"
            onClick={add}
            className="w-full border border-dashed border-border text-muted-foreground hover:bg-muted/50 hover:text-foreground"
          >
            <Plus className="mr-2 h-4 w-4" />
            Add Condition
          </Button>
        </div>

        <div className="flex items-center justify-end gap-3 border-t border-border/50 bg-muted/30 px-6 py-4">
          <Button variant="ghost" onClick={onClose}>
            Cancel
          </Button>
          <Button onClick={apply}>Apply Filters</Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import * as React from "react"
import { Calendar, ChevronLeft, ChevronRight, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet"
import { Separator } from "@/components/ui/separator"
import { useReferencingRecords, useForeignKeyOptions, useUpdateRecord } from "lemma-sdk/react"
import type { LemmaClient, Table, ColumnSchema } from "lemma-sdk"
import { cn } from "@/lib/utils"
import { enumPillClasses, typeBadgeClasses, isSystemField } from "./records-enum-utils"

interface DetailSheetProps {
  record: Record<string, unknown>
  table: Table
  client: LemmaClient
  podId?: string
  onClose: () => void
  onRecordChanged: () => void
  onDelete: () => void
  onNext?: () => void
  onPrevious?: () => void
  hasPrevious?: boolean
  hasNext?: boolean
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
  appearance?: "default" | "minimal" | "borderless" | "contained"
  density?: "compact" | "comfortable" | "spacious"
}

function detectTitle(record: Record<string, unknown>, columns: ColumnSchema[]): string {
  for (const name of ["title", "name", "label", "subject", "description"]) {
    const col = columns.find((c) => c.name === name)
    if (col && record[col.name] != null && String(record[col.name]).trim()) {
      return String(record[col.name])
    }
  }
  const first = columns.find((c) => !isSystemField(c) && c.type === "TEXT")
  if (first && record[first.name] != null) return String(record[first.name])
  return String(record[columns[0]?.name ?? "id"] ?? "Record")
}

export function DetailSheet({
  record,
  table,
  client,
  podId,
  onClose,
  onRecordChanged,
  onDelete,
  onNext,
  onPrevious,
  hasPrevious,
  hasNext,
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
  appearance = "default",
  density = "comfortable",
}: DetailSheetProps) {
  const pk = table.primary_key_column || "id"
  const recordId = String(record[pk] ?? "")
  const title = detectTitle(record, table.columns)
  const userColumns = table.columns.filter((c) => !isSystemField(c))
  const systemColumns = table.columns.filter((c) => isSystemField(c) && (c.name === "created_at" || c.name === "updated_at"))
  const fkColumns = userColumns.filter((c) => c.foreign_key)

  return (
    <Sheet open onOpenChange={(open) => !open && onClose()}>
      <SheetContent className={cn("w-full sm:max-w-lg gap-0 p-0", detailSurfaceClassName(appearance))}>
        <div className={cn("sticky top-0 z-10 backdrop-blur-sm", appearance === "borderless" ? "border-b-0 bg-background/80" : appearance === "minimal" ? "border-b border-border/15 bg-background/90" : "border-b border-border/50 bg-background/95")}>
          <SheetHeader className={density === "compact" ? "px-4 py-3" : density === "spacious" ? "px-7 py-5" : "px-6 py-4"}>
            <div className="flex items-center justify-between">
              <div className="min-w-0 flex-1">
                <SheetTitle className="text-lg font-semibold tracking-tight truncate">
                  {title}
                </SheetTitle>
                <div className="mt-1 flex items-center gap-2 text-xs text-muted-foreground">
                  <span className="rounded bg-muted px-1.5 py-0.5 font-mono text-[11px]">
                    {recordId.length > 8 ? `${recordId.slice(0, 4)}…${recordId.slice(-4)}` : recordId}
                  </span>
                  <span>{table.name}</span>
                </div>
              </div>
              <div className="flex items-center gap-1">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-7 w-7"
                  onClick={onPrevious}
                  disabled={!hasPrevious}
                >
                  <ChevronLeft className="h-4 w-4" />
                </Button>
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-7 w-7"
                  onClick={onNext}
                  disabled={!hasNext}
                >
                  <ChevronRight className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </SheetHeader>
        </div>

        <div className={cn("overflow-y-auto", density === "compact" ? "px-4 py-3" : density === "spacious" ? "px-7 py-6" : "px-6 py-4")}>
          <div className={cn("flex flex-col", density === "compact" ? "gap-4" : density === "spacious" ? "gap-7" : "gap-6")}>
          <FieldsSection
            record={record}
            columns={userColumns}
            client={client}
            podId={podId}
            tableName={table.name}
            recordId={recordId}
            onRecordChanged={onRecordChanged}
            updateVia={updateVia}
            updateFunctionName={updateFunctionName}
            foreignKeyLabels={foreignKeyLabels}
          />

          {fkColumns.map((col) => (
            <ReverseLookupSection
              key={col.name}
              client={client}
              podId={podId}
              table={table}
              column={col}
              recordId={recordId}
            />
          ))}

          {systemColumns.length > 0 && (
            <>
              <Separator className="bg-border/40" />
              <div className="space-y-2">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">
                  Timestamps
                </p>
                <div className="grid grid-cols-2 gap-3">
                  {systemColumns.map((col) => (
                    <div key={col.name}>
                      <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">
                        {col.name.replace(/_/g, " ")}
                      </p>
                      <p className="mt-0.5 text-sm text-foreground">
                        {formatTimestamp(record[col.name])}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
          </div>
        </div>

        <div className={cn("sticky bottom-0", appearance === "borderless" ? "border-t-0 bg-transparent" : appearance === "minimal" ? "border-t border-border/15 bg-transparent" : "border-t border-border/50 bg-muted/30", density === "compact" ? "px-4 py-2.5" : density === "spacious" ? "px-7 py-4" : "px-6 py-3")}>
          <div className="flex items-center justify-between">
            <Button
              variant="ghost"
              size="sm"
              className="text-destructive hover:bg-destructive/10 hover:text-destructive"
              onClick={onDelete}
            >
              <Trash2 className="mr-1.5 h-3.5 w-3.5" />
              Delete
            </Button>
            <Button variant="outline" size="sm" onClick={onClose}>
              Close
            </Button>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  )
}

function detailSurfaceClassName(appearance: "default" | "minimal" | "borderless" | "contained") {
  if (appearance === "borderless") return "border-0 shadow-xl ring-0"
  if (appearance === "minimal") return "border-0 shadow-none ring-0"
  if (appearance === "contained") return "border-border/70 shadow-xl"
  return "border-border/50"
}

function FieldsSection({
  record,
  columns,
  client,
  podId,
  tableName,
  recordId,
  onRecordChanged,
  updateVia,
  updateFunctionName,
  foreignKeyLabels,
}: {
  record: Record<string, unknown>
  columns: ColumnSchema[]
  client: LemmaClient
  podId?: string
  tableName: string
  recordId: string
  onRecordChanged: () => void
  updateVia?: "direct" | "function"
  updateFunctionName?: string
  foreignKeyLabels?: Record<string, string>
}) {
  const updateMutation = useUpdateRecord({ client, podId, tableName, recordId, updateVia, updateFunctionName })

  return (
    <div className="space-y-3">
      {columns.map((col) => (
        <div key={col.name} className="group">
          <div className="flex items-center gap-2">
            <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">
              {col.name.replace(/_/g, " ")}
            </p>
            <span className={typeBadgeClasses(col)}>
              {col.foreign_key ? "REF" : col.type.toLowerCase()}
            </span>
          </div>
          <FieldValue
            record={record}
            column={col}
            client={client}
            podId={podId}
            tableName={tableName}
            foreignKeyLabels={foreignKeyLabels}
            onSave={async (value) => {
              await updateMutation.update({ [col.name]: value })
              onRecordChanged()
            }}
          />
        </div>
      ))}
    </div>
  )
}

function FieldValue({
  record,
  column,
  client,
  podId,
  tableName,
  foreignKeyLabels,
  onSave,
}: {
  record: Record<string, unknown>
  column: ColumnSchema
  client: LemmaClient
  podId?: string
  tableName: string
  foreignKeyLabels?: Record<string, string>
  onSave: (value: unknown) => Promise<void>
}) {
  const value = record[column.name]
  const [editing, setEditing] = React.useState(false)
  const [draft, setDraft] = React.useState("")

  const fkOptions = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: column.name,
    labelField: foreignKeyLabels?.[column.name],
    enabled: !!column.foreign_key,
  })

  if (value == null || value === "") {
    return <p className="mt-0.5 text-sm italic text-muted-foreground">Empty</p>
  }

  if (column.type === "BOOLEAN") {
    const bool = Boolean(value)
    return (
      <span
        className={cn(
          "mt-0.5 inline-flex items-center rounded-full border px-2 py-0.5 text-xs font-medium",
          bool
            ? "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
            : "border-border bg-muted/50 text-muted-foreground",
        )}
      >
        {bool ? "Yes" : "No"}
      </span>
    )
  }

  if (column.type === "ENUM" && column.options?.length) {
    return (
      <span className={enumPillClasses(String(value), column.options)}>
        {String(value)}
      </span>
    )
  }

  if (column.foreign_key && fkOptions.options.length > 0) {
    const opt = fkOptions.options.find((o) => String(o.value) === String(value))
    return (
      <p className="mt-0.5 text-sm font-medium text-foreground">
        {opt?.label ?? String(value)}
      </p>
    )
  }

  if (column.type === "JSON") {
    const str = typeof value === "string" ? value : JSON.stringify(value, null, 2)
    return (
      <pre className="mt-0.5 max-h-40 overflow-auto rounded-lg border border-border/50 bg-muted/30 p-3 font-mono text-xs text-foreground">
        {str}
      </pre>
    )
  }

  if (column.type === "DATE" || column.type === "DATETIME") {
    return (
      <p className="mt-0.5 flex items-center gap-1.5 text-sm text-foreground">
        <Calendar className="h-3.5 w-3.5 text-muted-foreground" />
        {formatTimestamp(value)}
      </p>
    )
  }

  if (editing) {
    return (
      <input
        autoFocus
        className="mt-0.5 h-8 w-full rounded-md border border-border bg-background px-2 text-sm focus-ring"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={async (e) => {
          if (e.key === "Enter") {
            await onSave(column.type === "INTEGER" ? Number(draft) : draft)
            setEditing(false)
          }
          if (e.key === "Escape") setEditing(false)
        }}
        onBlur={async () => {
          await onSave(column.type === "INTEGER" ? Number(draft) : draft)
          setEditing(false)
        }}
      />
    )
  }

  return (
    <p
      className="mt-0.5 cursor-pointer rounded px-0.5 text-sm text-foreground transition-colors hover:bg-muted/50"
      onClick={() => {
        setDraft(String(value ?? ""))
        setEditing(true)
      }}
    >
      {String(value)}
    </p>
  )
}

function ReverseLookupSection({
  client,
  podId,
  table,
  column,
  recordId,
}: {
  client: LemmaClient
  podId?: string
  table: Table
  column: ColumnSchema
  recordId: string
}) {
  const ref = column.foreign_key?.references
  if (!ref) return null

  const [refTable, refCol] = ref.includes(".") ? ref.split(".") : [ref, "id"]

  const referencing = useReferencingRecords({
    client,
    podId,
    table: table.name,
    foreignKey: column.name,
    recordId,
    enabled: !!recordId,
  })

  if (!referencing.records.length && !referencing.isLoading) return null

  const col = referencing.columns

  return (
    <div className="space-y-2">
      <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground">
        Related {table.name} → {column.name}
      </p>
      {referencing.isLoading ? (
        <p className="text-xs text-muted-foreground">Loading…</p>
      ) : (
        <div className="space-y-1">
          {referencing.records.slice(0, 5).map((rec, i) => (
            <div
              key={i}
              className="rounded-md border border-border/50 bg-muted/30 px-3 py-2 text-xs text-foreground"
            >
              {col.map((c) => rec[c.field]).filter(Boolean).join(" · ") || "—"}
            </div>
          ))}
          {referencing.records.length > 5 && (
            <p className="text-[10px] text-muted-foreground">
              +{referencing.records.length - 5} more
            </p>
          )}
        </div>
      )}
    </div>
  )
}

function formatTimestamp(value: unknown): string {
  if (value == null) return "—"
  try {
    const d = new Date(String(value))
    return d.toLocaleDateString(undefined, {
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    })
  } catch {
    return String(value)
  }
}

